import React, { useMemo } from "react";
import KitsContainer from "../../helpers/FormContainer";
import { TreeSelect } from "primereact/treeselect";
import type { ITreeSelect } from "@lmb-it/kitsconcerto-types";
import type { TreeNode } from "primereact/treenode";
import { useKitsTheme } from "../../../contexts/Theme";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useTreeBuild } from "../hooks/useTreeBuild";

// Loose equality (==) handles string/number type mismatch between stored value and node key
const findNodeLabel = (nodes: TreeNode[], val: any): string | undefined => {
    for (const n of nodes) {
        // eslint-disable-next-line eqeqeq
        if (n.key == val) return n.label ?? undefined;
        if (n.children?.length) {
            const found = findNodeLabel(n.children, val);
            if (found !== undefined) return found;
        }
    }
    return undefined;
};

const filterParentsOnly = (nodes: TreeNode[]): TreeNode[] => {
    return nodes
        .filter(node => node.children && node.children.length > 0)
        .map(node => ({
            ...node,
            children: filterParentsOnly(node.children!),
        }));
};

const KitsTreeSelect = <T = any,>({ ref, ...rawProps }: ITreeSelect) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('TreeSelect', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        id,
        placeholder,
        required,
        disabled,
        helperText,
        attached,
        isFloatedLabel,
        inputSize,
        valueMode,
        isMultiple,
        localProps,
        withFilter,
        filterBy,
        hideError,
        onlyParentsWithChildren,
        resetFilterOnHide,
        scrollHeight,
        emptyMessage,
        showClear,
        containerStyle,
    } = props;

    const { nodes, value, handleChange } = useTreeBuild<T>({
        isStructured: props.isStructured,
        ref,
    });

    const filteredNodes = useMemo(() => {
        if (!onlyParentsWithChildren) return nodes;
        return filterParentsOnly(nodes);
    }, [nodes, onlyParentsWithChildren]);

    // Resolve the display label for single-select using loose equality to handle string/number key mismatch
    const selectedLabel = useMemo(() => {
        if (isMultiple || value == null) return undefined;
        return findNodeLabel(filteredNodes, value);
    }, [isMultiple, value, filteredNodes]);

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const Element = (
        <TreeSelect
            value={value}
            filter={withFilter}
            filterBy={filterBy ?? 'label'}
            options={filteredNodes}
            display={isMultiple ? valueMode : "comma"}
            selectionMode={isMultiple ? 'checkbox' : 'single'}
            onChange={handleChange}
            className="w-full"
            style={{ borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
            placeholder={placeholder}
            disabled={disabled}
            showClear={showClear ?? !required}
            resetFilterOnHide={resetFilterOnHide}
            scrollHeight={scrollHeight ? `${scrollHeight}px` : undefined}
            emptyMessage={emptyMessage}
            valueTemplate={selectedLabel ?? undefined}
            pt={{
                root: {
                    style: {
                        borderColor: borderColor,
                    }
                },
                // @ts-ignore
                node: ({ context }: any) => context?.selected ? {
                    style: {
                        backgroundColor: primaryColor,
                        color: 'white',
                    }
                } : context?.focused ? {
                    style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
                } : undefined,
                nodeCheckbox: {
                    box: ({ context }: any) => ({
                        style: {
                            borderColor: context?.checked ? primaryColor : borderColor,
                            backgroundColor: context?.checked ? primaryColor : 'transparent',
                        }
                    }),
                    icon: {
                        style: { color: 'white' }
                    }
                },
            }}
            {...localProps}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsTreeSelect;
